import React, { useEffect, useMemo, useRef, useState } from 'react';
import { Alert, Button, SafeAreaView, ScrollView, StyleSheet, Text, TextInput, View, ActivityIndicator, Platform } from 'react-native';
import AsyncStorage from '@react-native-async-storage/async-storage';
import { authorize, refresh, revoke, AuthConfiguration } from 'react-native-app-auth';

const OAUTH_CONFIG = {
  issuer: 'https://your-oauth-server.com',
  clientId: 'your_client_id',
  clientSecret: 'your_client_secret',
  redirectUrl: Platform.select({
    ios: 'com.yourapp://oauthredirect',
    android: 'com.yourapp://oauthredirect',
    default: 'com.yourapp://oauthredirect'
  }),
  scopes: ['openid', 'profile', 'email', 'offline_access'],
  serviceConfiguration: {
    authorizationEndpoint: 'https://your-oauth-server.com/oauth/authorize',
    tokenEndpoint: 'https://your-oauth-server.com/oauth/token',
    revocationEndpoint: 'https://your-oauth-server.com/oauth/revoke'
  }
};

const TOKEN_STORAGE_KEY = '@oauth_tokens_v1';

export default function App() {
  const [authState, setAuthState] = useState(null);
  const [loading, setLoading] = useState(true);
  const refreshTimer = useRef(null);

  const appAuthConfig = useMemo(() => ({
    issuer: OAUTH_CONFIG.issuer,
    clientId: OAUTH_CONFIG.clientId,
    clientSecret: OAUTH_CONFIG.clientSecret,
    redirectUrl: OAUTH_CONFIG.redirectUrl,
    scopes: OAUTH_CONFIG.scopes,
    serviceConfiguration: OAUTH_CONFIG.serviceConfiguration,
    additionalParameters: {}
  }), []);

  useEffect(() => {
    loadTokens();
    return () => {
      if (refreshTimer.current) clearTimeout(refreshTimer.current);
    };
  }, []);

  useEffect(() => {
    if (authState?.accessToken && authState?.accessTokenExpirationDate) {
      scheduleAutoRefresh(authState);
    } else if (refreshTimer.current) {
      clearTimeout(refreshTimer.current);
      refreshTimer.current = null;
    }
  }, [authState]);

  async function loadTokens() {
    try {
      const raw = await AsyncStorage.getItem(TOKEN_STORAGE_KEY);
      if (!raw) return;
      const parsed = JSON.parse(raw);
      setAuthState(parsed);
      const expiresAt = new Date(parsed.accessTokenExpirationDate).getTime();
      if (Date.now() >= expiresAt - 30000) {
        await handleRefresh(parsed);
      }
    } catch (e) {
      console.error(e);
    } finally {
      setLoading(false);
    }
  }

  async function persistTokens(tokens) {
    setAuthState(tokens);
    await AsyncStorage.setItem(TOKEN_STORAGE_KEY, JSON.stringify(tokens));
  }

  function scheduleAutoRefresh(tokens) {
    if (!tokens.refreshToken || !tokens.accessTokenExpirationDate) return;
    if (refreshTimer.current) clearTimeout(refreshTimer.current);

    const expiresAt = new Date(tokens.accessTokenExpirationDate).getTime();
    const refreshAt = Math.max(expiresAt - 60000, Date.now() + 5000);
    const delay = Math.max(refreshAt - Date.now(), 0);

    refreshTimer.current = setTimeout(() => {
      handleRefresh(tokens).catch(err => {
        console.error('Auto refresh failed', err);
      });
    }, delay);
  }

  async function handleLogin() {
    try {
      setLoading(true);
      const result = await authorize(appAuthConfig);
      const tokenData = {
        accessToken: result.accessToken,
        accessTokenExpirationDate: result.accessTokenExpirationDate,
        refreshToken: result.refreshToken,
        idToken: result.idToken,
        tokenType: result.tokenType,
        scopes: result.scopes
      };
      await persistTokens(tokenData);
    } catch (e) {
      Alert.alert('Login failed', e.message || 'Unable to authenticate');
    } finally {
      setLoading(false);
    }
  }

  async function handleRefresh(existing = authState) {
    if (!existing?.refreshToken) return;

    try {
      const result = await refresh({
        clientId: OAUTH_CONFIG.clientId,
        clientSecret: OAUTH_CONFIG.clientSecret,
        refreshToken: existing.refreshToken,
        scopes: OAUTH_CONFIG.scopes,
        serviceConfiguration: OAUTH_CONFIG.serviceConfiguration,
        useNonce: false
      });

      const nextTokens = {
        accessToken: result.accessToken,
        accessTokenExpirationDate: result.accessTokenExpirationDate,
        refreshToken: result.refreshToken || existing.refreshToken,
        idToken: result.idToken || existing.idToken,
        tokenType: result.tokenType || existing.tokenType,
        scopes: result.scopes || existing.scopes
      };

      await persistTokens(nextTokens);
    } catch (e) {
      console.error('Refresh failed', e);
      Alert.alert('Session expired', 'Please sign in again.');
      await handleLogout(false);
    }
  }

  async function handleLogout(showAlert = true) {
    try {
      if (authState?.accessToken && authState?.refreshToken) {
        await revoke({
          tokenToRevoke: authState.refreshToken,
          sendClientId: true,
          includeBasicAuth: true,
          clientId: OAUTH_CONFIG.clientId,
          clientSecret: OAUTH_CONFIG.clientSecret,
          serviceConfiguration: OAUTH_CONFIG.serviceConfiguration
        });
      }
    } catch (e) {
      console.error('Revoke failed', e);
    } finally {
      if (refreshTimer.current) clearTimeout(refreshTimer.current);
      refreshTimer.current = null;
      setAuthState(null);
      await AsyncStorage.removeItem(TOKEN_STORAGE_KEY);
      if (showAlert) Alert.alert('Signed out');
    }
  }

  const expiresText = authState?.accessTokenExpirationDate
    ? new Date(authState.accessTokenExpirationDate).toLocaleString()
    : 'N/A';

  return (
    <SafeAreaView style={styles.container}>
      <ScrollView contentContainerStyle={styles.content}>
        <Text style={styles.title}>OAuth 2.0 Mobile Auth</Text>

        <View style={styles.card}>
          <Text style={styles.label}>Issuer</Text>
          <TextInput style={styles.input} value={OAUTH_CONFIG.issuer} editable={false} />

          <Text style={styles.label}>Client ID</Text>
          <TextInput style={styles.input} value={OAUTH_CONFIG.clientId} editable={false} />

          <Text style={styles.label}>Client Secret</Text>
          <TextInput style={styles.input} value={OAUTH_CONFIG.clientSecret} editable={false} secureTextEntry />

          <Text style={styles.label}>Access Token</Text>
          <TextInput
            style={[styles.input, styles.multiline]}
            value={authState?.accessToken || ''}
            placeholder="Not signed in"
            editable={false}
            multiline
          />

          <Text style={styles.label}>Refresh Token</Text>
          <TextInput
            style={[styles.input, styles.multiline]}
            value={authState?.refreshToken || ''}
            placeholder="Not signed in"
            editable={false}
            multiline
          />

          <Text style={styles.label}>Expires At</Text>
          <Text style={styles.value}>{expiresText}</Text>

          <Text style={styles.label}>Scopes</Text>
          <Text style={styles.value}>{authState?.scopes?.join(', ') || 'N/A'}</Text>
        </View>

        <View style={styles.actions}>
          {loading ? (
            <ActivityIndicator size="large" />
          ) : authState ? (
            <>
              <Button title="Refresh Token" onPress={() => handleRefresh()} />
              <View style={styles.spacer} />
              <Button title="Logout" color="#d9534f" onPress={() => handleLogout()} />
            </>
          ) : (
            <Button title="Login with OAuth 2.0" onPress={handleLogin} />
          )}
        </View>
      </ScrollView>
    </SafeAreaView>
  );
}

